// Build WhatsApp + Telegram messages from alert payload
const body = $input.first().json.body || $input.first().json;
const service = body.service || 'unknown';
const classification = body.classification || 'unknown';
const severity = body.severity || 'medium';
const summary = body.summary || 'No summary';
const suggested_fix = body.suggested_fix || 'No fix suggested';
const incident_id = body.incident_id || `${service}_${Date.now()}`;
const kind = body.kind || 'alert'; // 'alert' or 'recovery' or 'onboarded' or 'onboarding_failed'

const sevEmoji = {critical: '\ud83d\udd34', high: '\ud83d\udfe0', medium: '\ud83d\udfe1', low: '\ud83d\udd35', info: '\u2139\ufe0f'};
const sevHe = {critical: '\u05e7\u05e8\u05d9\u05d8\u05d9', high: '\u05d2\u05d1\u05d5\u05d4', medium: '\u05d1\u05d9\u05e0\u05d5\u05e0\u05d9', low: '\u05e0\u05de\u05d5\u05da', info: '\u05de\u05d9\u05d3\u05e2'};

let whatsappText = '';
let telegramText = '';

if (kind === 'recovery') {
  whatsappText = `\u2705 \u05e9\u05d9\u05e8\u05d5\u05ea \u05d7\u05d6\u05e8 \u05dc\u05e4\u05e2\u05d5\u05dc\u05d4 \u2014 ${service}\n\n${summary}`;
  telegramText = whatsappText;
} else if (kind === 'onboarded') {
  whatsappText = `\u2705 \u05e9\u05d9\u05e8\u05d5\u05ea \u05d7\u05d3\u05e9 \u05d4\u05e6\u05d8\u05e8\u05e3 \u05dc-mesh\n\n\u05e9\u05dd: ${service}\n${summary}`;
  telegramText = whatsappText;
} else if (kind === 'onboarding_failed') {
  whatsappText = `\ud83d\udfe0 \u05e9\u05d9\u05e8\u05d5\u05ea \u05d7\u05d3\u05e9 \u05dc\u05d0 \u05d4\u05e6\u05d8\u05e8\u05e3 \u05dc-mesh\n\n\u05e9\u05dd: ${service}\n\u05e1\u05d9\u05d1\u05d4: ${summary}\n\n\u05ea\u05d9\u05e7\u05d5\u05df: ${suggested_fix}`;
  telegramText = whatsappText;
} else {
  whatsappText = `${sevEmoji[severity] || '\ud83d\udea8'} \u05d4\u05ea\u05e8\u05d0\u05ea \u05de\u05e2\u05e8\u05db\u05ea \u2014 Sivan Stack\n\n\u05e9\u05d9\u05e8\u05d5\u05ea: ${service}\n\u05d7\u05d5\u05de\u05e8\u05d4: ${sevHe[severity] || severity}\n\u05d6\u05de\u05df: ${new Date().toLocaleString('he-IL', {timeZone: 'Asia/Jerusalem'})}\n\n\u05de\u05d4 \u05e7\u05e8\u05d4:\n${summary}\n\n\u05d4\u05de\u05dc\u05e6\u05d4 \u05dc\u05ea\u05d9\u05e7\u05d5\u05df:\n${suggested_fix}\n\nIncident ID: ${incident_id}`;
  telegramText = whatsappText;
}

return [{json: {
  whatsappText,
  telegramText,
  service, classification, severity, summary, suggested_fix, incident_id, kind
}}];
